const input = $input.first().json.body || $input.first().json;

const imageUrl = input.image_url || '';
const animationStyle = input.animation_style || 'zoom_in';
const duration = input.duration || '8s';
const resolution = input.resolution || '720p';
const customPrompt = input.custom_prompt || '';
const generateAudio = input.generate_audio !== false;

if (!imageUrl) throw new Error('Missing image_url');

// Prompts optimisés pour Veo 3.1
const stylePrompts = {
  'zoom_in': 'Slow cinematic zoom in on the subject, smooth professional camera movement, studio lighting, high-end product showcase, 4K quality',
  'zoom_out': 'Slow cinematic zoom out revealing the full scene and context, smooth dolly movement, professional cinematography',
  'pan_left': 'Smooth horizontal camera tracking shot from right to left, cinematic dolly movement, professional lighting',
  'pan_right': 'Smooth horizontal camera tracking shot from left to right, cinematic dolly movement, professional lighting',
  'float': 'Gentle floating motion with subtle vertical movement, dreamy atmosphere, soft bokeh background, ethereal quality',
  'rotate': 'Slow orbital camera movement rotating 360 degrees around the subject, smooth steady motion, professional turntable effect',
  'sparkle': 'Magical particle effects and light sparkles appearing around the subject, enchanting golden glow, premium product reveal',
  'reveal': 'Dramatic product reveal with volumetric light rays, lens flare effects, premium cinematic showcase, luxury feel',
  'breathe': 'Subtle breathing pulsation effect, gentle living photograph style, minimal movement, artistic and elegant',
  'custom': customPrompt || 'Cinematic professional motion, smooth camera movement, high quality'
};

const prompt = stylePrompts[animationStyle] || stylePrompts['zoom_in'];

// Veo 3.1 accepte: 4s, 6s, 8s
let veoDuration = duration;
if (!veoDuration.endsWith('s')) veoDuration = veoDuration + 's';
if (!['4s', '6s', '8s'].includes(veoDuration)) veoDuration = '8s';

// Resolution: 720p ou 1080p
const veoResolution = ['720p', '1080p'].includes(resolution) ? resolution : '720p';

return {
  image_url: imageUrl,
  prompt: prompt,
  duration: veoDuration,
  resolution: veoResolution,
  generate_audio: generateAudio,
  animation_style: animationStyle
};

const r = $input.first().json;

if (!r.request_id) {
  throw new Error('No request_id received from FAL: ' + JSON.stringify(r));
}

return {
  request_id: r.request_id,
  status_url: r.status_url || '',
  response_url: r.response_url || '',
  status: 'processing'
};

const input = $input.first().json.body || $input.first().json;
const requestId = input.request_id;

if (!requestId) {
  throw new Error('Missing request_id');
}

return { request_id: requestId };

const data = $input.first().json;
const requestId = $('Extract Status Request').item.json.request_id;

let videoUrl = '';

if (data.video && data.video.url) {
  videoUrl = data.video.url;
} else if (data.output && data.output.video && data.output.video.url) {
  videoUrl = data.output.video.url;
} else if (data.data && data.data.video && data.data.video.url) {
  videoUrl = data.data.video.url;
} else if (data.url) {
  videoUrl = data.url;
}

if (!videoUrl) {
  throw new Error('Could not find video URL in Veo response: ' + JSON.stringify(data).substring(0, 500));
}

return {
  success: true,
  status: 'completed',
  video_url: videoUrl,
  model: 'veo3.1',
  request_id: requestId
};
